INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('judicial-de09bf8b-moex-00079', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-113-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'single_choice', '甲搶劫銀樓後，商請其女友乙協助，使其躲藏於乙之租屋處，兩人共同將得手金飾燒熔成金塊。 有關乙之刑事責任，下列敘述何者正確？', '["成立藏匿人犯罪", "成立準強盜罪", "不成立犯罪", "成立湮滅刑事證據罪之幫助犯"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "559c5671d4e3", "answer_pdf_sha1": "a045179453c3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "201", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00080', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-113-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'single_choice', '依實務見解，下列情形中何者不適用刑法第185條之4交通事故逃逸罪之規定而處罰？', '["甲駕車闖紅燈，不慎撞傷乙後即離開現場", "甲依規定停等紅燈時，遭乙駕車從後追撞，甲見乙因而受傷後，仍離開現場", "甲騎乘自行車遇見仇人乙正在過馬路，遂故意騎車衝撞乙，致乙倒地受傷後，即加速駛離現場", "甲超速駕車通過十字路口，撞上闖紅燈之乙，致乙死亡，甲見乙既然已死亡，沒有救助需要， 遂駕車駛離現場"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "559c5671d4e3", "answer_pdf_sha1": "a045179453c3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "201", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00081', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-113-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'single_choice', '有關阻塞公眾逃生通道罪的敘述，下列何者錯誤？', '["地下室屬於防空避難之用，並非本罪所指的逃生通道", "在集合住宅樓梯間暫時放置仍在滴水的雨傘，並不構成阻塞公眾逃生通道", "在通往公寓頂樓的逃生門上私自加裝門鎖，導致其他住戶無法通往頂樓，是阻塞公眾逃生通道", "公眾得出入之場所指的是不特定人得隨時出入之場所"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "559c5671d4e3", "answer_pdf_sha1": "a045179453c3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "201", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00082', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-113-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'single_choice', '甲意圖供行使之用，而在乙的信用卡背面冒簽乙姓名之行為，若依實務見解，甲成立何罪？', '["刑法第201條之1第1項偽造支付工具罪", "刑法第201條第1項偽造有價證券罪", "刑法第212條偽造特種文書罪", "刑法第210條偽造私文書罪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "559c5671d4e3", "answer_pdf_sha1": "a045179453c3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "201", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00083', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-113-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'single_choice', '市府建設課公務員甲與其配偶乙近來因投資理財失利，損失慘重，兩人積極謀求填補財務坑洞。 經過一段時間，甲、乙共同決議，先由甲向建商要錢，再由乙出面拿錢。於是甲向建商A表示， 如果要讓建案如期動工，須於本月底前依其指示交付新臺幣3百萬元給乙。A為求該建案如期動 工，乃依甲之指示，以行李箱裝現金新臺幣3百萬在火車站交付給乙。甲、乙之行為應如何論罪？', '["甲、乙成立刑法第121條職務收賄罪之共同正犯", "甲、乙成立刑法第122條違背職務收賄罪之共同正犯", "甲成立刑法第121條職務收賄罪之正犯，乙成立刑法第121條職務收賄罪之幫助犯", "甲成立刑法第122條違背職務收賄罪之正犯，乙成立刑法第122條違背職務收賄罪之幫助犯"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "559c5671d4e3", "answer_pdf_sha1": "a045179453c3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "201", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00084', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-113-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'single_choice', '下列敘述何者牴觸罪刑法定原則？', '["在機場行竊，成立加重竊盜罪", "未經他人允許，偷用他人未加密的無線網路（俗稱蹭網），成立竊盜罪", "私接電線竊取他人電能，成立竊盜罪", "在旗津渡輪上扒竊他人錢包，成立加重竊盜罪"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "559c5671d4e3", "answer_pdf_sha1": "a045179453c3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "201", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00085', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-113-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'single_choice', '甲欲自殺，上網教唆乙與其一同自殺而謀為同死，乙前往甲家與甲一起燒炭自殺，乙因而死亡， 甲卻因吸入較少一氧化碳而獲救。有關甲之刑責，下列敘述何者正確？', '["甲成立加工自殺罪", "甲未死亡，故不得適用謀為同死而免除其刑之規定", "甲成立殺人罪之幫助犯", "甲成立受囑託殺人罪"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "559c5671d4e3", "answer_pdf_sha1": "a045179453c3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "201", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00086', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-113-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'single_choice', '甲和Ａ是情侶，某日因Ａ欲分手，雙方在路上發生激烈爭吵，A憤而離去。一小時後，甲愈想愈 氣，趁A不在家時，憤而將三秒膠注入A所有機車之鑰匙孔，A因而無法騎車。有關甲之刑責， 依實務見解，成立何罪？', '["刑法第304條第2項強制未遂罪", "刑法第304條第1項強制既遂罪", "刑法第302條第1項妨害行動自由罪", "刑法第354條毀損器物罪"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "559c5671d4e3", "answer_pdf_sha1": "a045179453c3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "201", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 22, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00087', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-113-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'single_choice', '甲利用社交軟體貼文，該內容為足以毀損 A 名譽之事，經檢察官起訴刑法第 310 條第 2 項誹謗 罪，但後來法院卻判決不成立誹謗罪，下列何者不會是法院的理由？', '["甲貼文具有散布於眾之意圖", "甲貼文出於善意且為保護合法之利益", "甲貼文屬公務員因職務而報告", "甲貼文出於善意且內容為可受公評之事"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "559c5671d4e3", "answer_pdf_sha1": "a045179453c3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "201", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00088', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-113-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'single_choice', '下列行為，何者不該當於刑法竊聽竊錄罪中所謂「窺視、竊聽或竊錄他人非公開之活動、言論、 談話或身體隱私部位」？', '["在他人家中安裝竊聽器，錄下他人在家中之對話", "以錄音筆偷錄下立委候選人公開演說之內容", "在觀光飯店房間內安裝針孔攝影機，拍攝他人住宿時之活動", "在捷運站手扶梯上，將手機伸至女性乘客裙底，拍攝其裙下風光"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "559c5671d4e3", "answer_pdf_sha1": "a045179453c3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "201", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL)
